```
def is_valid(grid, row, col, num):
    # Check if num already exists in the same row
    if num in grid[row]:
        return False

    # Check if num already exists in the same column
    for i in range(len(grid)):
        if grid[i][col] == num:
            return False

    # Check if num violates the consecutive rule
    if col >= 2 and grid[row][col-1] == grid[row][col-2] == num:
        return False

    if row >= 2 and grid[row-1][col] == grid[row-2][col] == num:
        return False

    return True

def solve_puzzle(grid):
    for row in range(len(grid)):
        for col in range(len(grid)):
            if grid[row][col] == "_":
                for num in ["0", "1"]:
                    if is_valid(grid, row, col, num):
                        grid[row][col] = num
                        if solve_puzzle(grid):
                            return True
                        grid[row][col] = "_"
                return False

    return True

def print_grid(grid):
    for row in grid:
        print("".join(row))

# Example binary puzzle
puzzle = [
    ["1", "_", "0", "_", "_"],
    ["_", "_", "0", "0", "_"],
    ["_", "0", "0", "_", "1"],
    ["_", "_", "_", "_", "_"],
    ["0", "0", "1", "_", "_"]
]

# Solve the puzzle
solve_puzzle(puzzle)

# Print the solved puzzle
print_grid(puzzle)
```

